// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

#define MOD 1000000007

// Function to calculate the modular inverse
uint64_t mod_inverse(uint64_t a) {
    uint64_t m0 = MOD;
    uint64_t y = 0, x = 1;
    if (MOD == 1)
        return 0;
    while (a > 1) {
        uint64_t q = a / MOD;
        uint64_t t = MOD;
        MOD = a % MOD; a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0)
        x += m0;
    return x;
}

// Function to construct the minimal polynomial
void construct_polynomial(int n, uint64_t* ai) {
    uint64_t* coefficients = (uint64_t*)malloc((n + 1) * sizeof(uint64_t));
    coefficients[0] = 1;
    for (int i = 0; i < n; i++) {
        uint64_t* new_coefficients = (uint64_t*)malloc((2 * n + 1) * sizeof(uint64_t));
        for (int j = 0; j <= 2 * n; j++)
            new_coefficients[j] = 0;
        for (int j = 0; j <= n; j++) {
            new_coefficients[j] += coefficients[j];
            new_coefficients[j + n + 1] -= ai[i] * coefficients[j];
        }
        free(coefficients);
        coefficients = new_coefficients;
    }
    printf("%d\n", n * 2);
    for (int i = 0; i <= n * 2; i++)
        printf("%llu ", coefficients[i] % MOD);
    printf("\n");
    free(coefficients);
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        uint64_t* ai = (uint64_t*)malloc(n * sizeof(uint64_t));
        for (int i = 0; i < n; i++)
            scanf("%llu", &ai[i]);
        construct_polynomial(n, ai);
        free(ai);
    }
    return 0;
}

